import pytest
import requests

def test_primary_holder_transaction_succeeds(joint_account_fixture, primary_holder_token):
    account_id = joint_account_fixture["account_id"]
    headers = {"Authorization": f"Bearer {primary_holder_token}"}
    payload = {"type": "debit", "amount": 100.00, "currency": "USD"}

    response = requests.post(
        f"{<BASE_URL>}/accounts/{account_id}/joint",
        json=payload,
        headers=headers,
    )

    assert response.status_code in (200, 201), (
        f"Expected 200/201, got {response.status_code}: {response.text}"
    )
    body = response.json()
    assert "transaction_id" in body, "Response missing transaction_id"
    assert "balance" in body, "Response missing balance"
    assert body["balance"] == pytest.approx(
        joint_account_fixture["initial_balance"] - 100.00, abs=0.01
    )

import requests

def test_secondary_holder_ownership_change_returns_403(
    joint_account_fixture, secondary_holder_token, alternate_user_id
):
    account_id = joint_account_fixture["account_id"]
    headers = {"Authorization": f"Bearer {secondary_holder_token}"}
    payload = {"new_primary_owner_id": alternate_user_id}

    response = requests.patch(
        f"{<BASE_URL>}/accounts/{account_id}/joint",
        json=payload,
        headers=headers,
    )

    assert response.status_code == 403, (
        f"Expected 403, got {response.status_code}: {response.text}"
    )
    body = response.json()
    assert "error" in body or "code" in body, "Response missing error descriptor"

    verify = requests.get(
        f"{<BASE_URL>}/accounts/{account_id}/joint",
        headers={"Authorization": f"Bearer {<ADMIN_TOKEN>}"},
    )
    assert verify.json()["primary_owner_id"] == joint_account_fixture["primary_owner_id"]

import requests
import pytest

DAILY_LIMIT = 10_000.00

def test_transaction_at_exact_daily_limit_boundary(
    joint_account_at_limit_fixture, primary_holder_token
):
    account_id = joint_account_at_limit_fixture["account_id"]
    headers = {"Authorization": f"Bearer {primary_holder_token}"}

    at_limit_payload = {"type": "debit", "amount": DAILY_LIMIT, "currency": "USD"}
    r1 = requests.post(
        f"{<BASE_URL>}/accounts/{account_id}/joint",
        json=at_limit_payload,
        headers=headers,
    )
    assert r1.status_code in (200, 201), (
        f"At-limit debit failed: {r1.status_code} {r1.text}"
    )
    assert r1.json()["balance"] == pytest.approx(0.00, abs=0.01)

    over_limit_payload = {"type": "debit", "amount": 0.01, "currency": "USD"}
    r2 = requests.post(
        f"{<BASE_URL>}/accounts/{account_id}/joint",
        json=over_limit_payload,
        headers=headers,
    )
    assert r2.status_code in (422, 429), (
        f"Expected limit-exceeded error, got {r2.status_code}: {r2.text}"
    )

